import React from 'react';
import { NavLink } from 'react-router-dom';

const NAV_LINKS = [
  { to: '/', label: 'Home' },
  { to: '/raise-ticket', label: 'Raise Ticket' },
  { to: '/chatbot', label: 'Chatbot' },
  { to: '/my-tickets', label: 'My Tickets' },
  { to: '/admin', label: 'Admin Dashboard' },
];

export default function Navbar() {
  return (
    <nav className="sticky top-0 z-50 bg-white/95 backdrop-blur-md border-b border-gray-200 flex items-center px-8 h-16 gap-6">
      {/* Logo */}
      <NavLink to="/" className="flex items-center gap-2.5 no-underline">
        <div className="w-10 h-10 bg-navy rounded-lg flex items-center justify-center relative overflow-hidden">
          <div className="absolute w-4 h-4 rounded-full bg-green top-1 left-1" />
          <div className="absolute w-3 h-3 rounded-full bg-blue-400 bottom-1.5 right-1" />
        </div>
        <div className="flex flex-col leading-tight">
          <span className="font-head font-black text-base text-navy tracking-widest">SEGULA</span>
          <span className="text-[9px] text-gray-400 tracking-[2px] uppercase">Technologies</span>
        </div>
      </NavLink>
      <span className="font-head font-semibold text-base text-gray-900">SupportAI</span>

      {/* Nav Links */}
      <div className="flex gap-1 ml-auto items-center">
        {NAV_LINKS.map(({ to, label }) => (
          <NavLink
            key={to}
            to={to}
            end={to === '/'}
            className={({ isActive }) =>
              `nav-link ${isActive ? 'active' : ''}`
            }
          >
            {label}
          </NavLink>
        ))}
      </div>

      {/* Status */}
      <div className="flex items-center gap-1.5 text-sm text-green font-medium ml-4">
        <span className="w-2 h-2 rounded-full bg-green pulse-dot" />
        System Online
      </div>

      {/* User */}
      <button className="w-9 h-9 rounded-full border border-gray-200 flex items-center justify-center text-gray-400 hover:border-green hover:text-green transition-colors ml-3">
        <svg xmlns="http://www.w3.org/2000/svg" className="w-4 h-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
          <path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2" /><circle cx="12" cy="7" r="4" />
        </svg>
      </button>
    </nav>
  );
}
